/**
 * TESTS - GO BOARD ENGINE
 *
 * Local tests using a mock SpreadsheetApp.
 * Run with: node Test.js
 *
 * For Google Apps Script runtime tests, see the runTestsInSpreadsheet() function
 * which exercises the code using the real GAS API.
 */

// --- Mock SpreadsheetApp for local testing ---
var MockSheet = function(name) {
  this.name_ = name;
  this.data_ = [];
  for (var r = 0; r < 19; r++) {
    this.data_[r] = [];
    for (var c = 0; c < 19; c++) {
      this.data_[r][c] = "";
    }
  }
  this.bgColors_ = [];
  this.fontColors_ = [];
  for (var r = 0; r < 19; r++) {
    this.bgColors_[r] = [];
    this.fontColors_[r] = [];
    for (var c = 0; c < 19; c++) {
      this.bgColors_[r][c] = "";
      this.fontColors_[r][c] = "";
    }
  }
  this.borders_ = [];
  for (var r = 0; r < 19; r++) {
    this.borders_[r] = [];
    for (var c = 0; c < 19; c++) {
      this.borders_[r][c] = null;
    }
  }
};
MockSheet.prototype.getName = function() { return this.name_; };
MockSheet.prototype.getRange = function(a1) {
  return new MockRange(this, a1);
};
MockSheet.prototype.setValue = function(val) { this.value_ = val; };
MockSheet.prototype.getValue = function() { return this.value_; };
MockSheet.prototype.setBackground = function(c) { this.bg_ = c; };
MockSheet.prototype.getBackground = function() { return this.bg_; };
MockSheet.prototype.setFontColor = function(c) { this.fc_ = c; };
MockSheet.prototype.getFontColor = function() { return this.fc_; };
MockSheet.prototype.setHorizontalAlignment = function(h) { this.hAlign_ = h; };
MockSheet.prototype.setVerticalAlignment = function(v) { this.vAlign_ = v; };
MockSheet.prototype.setFontSize = function(s) { this.fontSize_ = s; };
MockSheet.prototype.getSheetId = function() { return this.name_.charCodeAt(0); };

var MockRange = function(sheet, a1Notation) {
  this.sheet_ = sheet;
  this.a1_ = a1Notation;
  var coords = a1ToCoords(a1Notation);
  this.row_ = coords[0];
  this.col_ = coords[1];
  this.rows_ = coords[2] || 1;
  this.cols_ = coords[3] || 1;
};
MockRange.prototype.getA1Notation = function() { return this.a1_; };
MockRange.prototype.getRow = function() { return this.row_; };
MockRange.prototype.getColumn = function() { return this.col_; };
MockRange.prototype.getNumRows = function() { return this.rows_; };
MockRange.prototype.getNumColumns = function() { return this.cols_; };
MockRange.prototype.getSheet = function() { return this.sheet_; };
MockRange.prototype.getValue = function() {
  if (this.rows_ === 1 && this.cols_ === 1) {
    return this.sheet_.getValue();
  }
  return null;
};
MockRange.prototype.getValues = function() {
  var data = this.sheet_.data_;
  var result = [];
  for (var r = this.row_ - 1; r < this.row_ - 1 + this.rows_ && r < 19; r++) {
    var row = [];
    for (var c = this.col_ - 1; c < this.col_ - 1 + this.cols_ && c < 19; c++) {
      row.push(data[r][c]);
    }
    result.push(row);
  }
  return result;
};
MockRange.prototype.setValue = function(val) {
  this.sheet_.setValue(val);
};
MockRange.prototype.setValues = function(arr) {
  for (var r = 0; r < arr.length; r++) {
    for (var c = 0; c < arr[r].length; c++) {
      if (this.row_ - 1 + r < 19 && this.col_ - 1 + c < 19) {
        this.sheet_.data_[this.row_ - 1 + r][this.col_ - 1 + c] = arr[r][c];
      }
    }
  }
};
MockRange.prototype.setBackground = function(c) {
  if (this.rows_ === 1 && this.cols_ === 1) {
    this.sheet_.setBackground(c);
    return;
  }
  for (var r = 0; r < this.rows_ && this.row_ - 1 + r < 19; r++) {
    for (var c = 0; c < this.cols_ && this.col_ - 1 + c < 19; c++) {
      this.sheet_.bgColors_[this.row_ - 1 + r][this.col_ - 1 + c] = c;
    }
  }
};
MockRange.prototype.setBackgrounds = function(arr) {
  for (var r = 0; r < arr.length; r++) {
    for (var c = 0; c < arr[r].length; c++) {
      if (this.row_ - 1 + r < 19 && this.col_ - 1 + c < 19) {
        this.sheet_.bgColors_[this.row_ - 1 + r][this.col_ - 1 + c] = arr[r][c];
      }
    }
  }
};
MockRange.prototype.setFontColors = function(arr) {
  for (var r = 0; r < arr.length; r++) {
    for (var c = 0; c < arr[r].length; c++) {
      if (this.row_ - 1 + r < 19 && this.col_ - 1 + c < 19) {
        this.sheet_.fontColors_[this.row_ - 1 + r][this.col_ - 1 + c] = arr[r][c];
      }
    }
  }
};
MockRange.prototype.setFontColor = function(c) {
  this.sheet_.setFontColor(c);
};
MockRange.prototype.setHorizontalAlignment = function(h) {
  this.sheet_.horizontalAlignment_ = h;
};
MockRange.prototype.setVerticalAlignment = function(v) {
  this.sheet_.verticalAlignment_ = v;
};
MockRange.prototype.setFontSize = function(s) {
  this.sheet_.fontSize_ = s;
};
MockRange.prototype.setBorder = function() {};
MockRange.prototype.clearContent = function() {
  for (var r = this.row_ - 1; r < this.row_ - 1 + this.rows_ && r < 19; r++) {
    for (var c = this.col_ - 1; c < this.col_ - 1 + this.cols_ && c < 19; c++) {
      this.sheet_.data_[r][c] = "";
    }
  }
};
MockRange.prototype.copyTo = function(targetRange, type, pasteFormat) {
  if (type === "PASTE_VALUES" && pasteFormat === false) {
    var srcValues = this.getValues();
    for (var r = 0; r < srcValues.length; r++) {
      for (var c = 0; c < srcValues[r].length; c++) {
        if (targetRange.row_ - 1 + r < 19 && targetRange.col_ - 1 + c < 19) {
          targetRange.sheet_.data_[targetRange.row_ - 1 + r][targetRange.col_ - 1 + c] = srcValues[r][c];
        }
      }
    }
  }
};

function a1ToCoords(a1) {
  var colMatch = a1.match(/[A-Z]+/);
  var rowMatch = a1.match(/[0-9]+/);
  if (!colMatch || !rowMatch) return [0, 0, 1, 1];
  var col = 0;
  for (var i = 0; i < colMatch[0].length; i++) {
    col = col * 26 + (colMatch[0].charCodeAt(i) - 64);
  }
  var row = parseInt(rowMatch[0], 10);
  // Parse dimensions from ranges like "A1:S19"
  var split = a1.split(":");
  var rows = 1, cols = 1;
  if (split.length === 2) {
    var endCoords = a1ToCoords(split[1]);
    rows = endCoords[2] - row + 1;
    cols = endCoords[3] - col + 1;
  }
  return [row, col, rows, cols];
}

var MockSpreadsheet = function() {
  this.sheets_ = {};
  // Create default sheets
  this.addSheet("Current Board");
};
MockSpreadsheet.prototype.addSheet = function(name) {
  this.sheets_[name] = new MockSheet(name);
  return this.sheets_[name];
};
MockSpreadsheet.prototype.getSheetByName = function(name) {
  return this.sheets_[name] || null;
};
MockSpreadsheet.prototype.insertSheet = function(name) {
  if (!this.sheets_[name]) {
    this.addSheet(name);
  }
  return this.sheets_[name];
};
MockSpreadsheet.prototype.getActiveSheet = function() {
  return this.sheets_["Current Board"];
};

var mockSS = null;

var SpreadsheetApp = {
  CopyPasteType: { PASTE_VALUES: "PASTE_VALUES" },
  BorderStyle: { SOLID: "SOLID" },
  getActiveSpreadsheet: function() { return mockSS; },
};

// --- Re-define constants and functions using the mock ---

var B_COLOR = "#000000";
var B_STONE = "●";
var W_COLOR = "#ffffff";
var W_STONE = "◘";
var BOARD_COLOR = "#f3b562";
var BOARD_RANGE = "A1:S19";
var MOVE_CELL = "U1";
var RESET_CELL = "U2";
var UNDO_CELL = "U3";

function getGroup(r, c, boardData, visited) {
  visited = visited || new Set();
  var key = r + "," + c;
  if (visited.has(key)) return [];
  var color = boardData[r][c];
  if (!color) return [];
  visited.add(key);
  var group = [{ r: r, c: c }];
  var neighbors = [
    { r: r, c: c + 1 },
    { r: r, c: c - 1 },
    { r: r + 1, c: c },
    { r: r - 1, c: c },
  ];
  for (var i = 0; i < neighbors.length; i++) {
    var n = neighbors[i];
    if (boardData[n.r] && boardData[n.r][n.c] === color) {
      group = group.concat(getGroup(n.r, n.c, boardData, visited));
    }
  }
  return group;
}

function groupHasLiberties(group, boardData) {
  for (var i = 0; i < group.length; i++) {
    var cell = group[i];
    var neighbors = [
      { r: cell.r, c: cell.c + 1 },
      { r: cell.r, c: cell.c - 1 },
      { r: cell.r + 1, c: cell.c },
      { r: cell.r - 1, c: cell.c },
    ];
    for (var j = 0; j < neighbors.length; j++) {
      var n = neighbors[j];
      if (boardData[n.r] && boardData[n.r][n.c] === "") {
        return true;
      }
    }
  }
  return false;
}

function checkAndRedraw(sheet) {
  var range = sheet.getRange(BOARD_RANGE);
  var boardData = range.getValues();

  var checked = new Set();

  for (var r = 0; r < boardData.length; r++) {
    for (var c = 0; c < boardData[r].length; c++) {
      var key = r + "," + c;
      if (checked.has(key)) continue;
      var val = boardData[r][c];
      if (!val) continue;
      var group = getGroup(r, c, boardData);
      var members = [];
      for (var k = 0; k < group.length; k++) {
        members.push(group[k].r + "," + group[k].c);
      }
      for (var k = 0; k < members.length; k++) {
        checked.add(members[k]);
      }
      if (!groupHasLiberties(group, boardData)) {
        for (var k = 0; k < group.length; k++) {
          boardData[group[k].r][group[k].c] = "";
        }
      }
    }
  }

  range.setValues(boardData);

  var bgColors = [];
  var fontColors = [];
  for (var r = 0; r < boardData.length; r++) {
    var bgRow = [];
    var fontRow = [];
    for (var c = 0; c < boardData[r].length; c++) {
      var val = boardData[r][c];
      if (val === B_STONE || val === W_STONE) {
        fontRow.push("black");
      } else {
        fontRow.push(BOARD_COLOR);
      }
      bgRow.push(BOARD_COLOR);
    }
    bgColors.push(bgRow);
    fontColors.push(fontRow);
  }

  range.setBackgrounds(bgColors);
  range.setFontColors(fontColors);
  range.setHorizontalAlignment("center");
  range.setVerticalAlignment("middle");
  range.setFontSize(20);
}

function resetBoard() {
  var sheet = SpreadsheetApp.getActiveSheet();
  var range = sheet.getRange(BOARD_RANGE);
  range.clearContent();
  range.setBackground(BOARD_COLOR);
  range.setBorder(true, true, true, true, true, true, "black", SpreadsheetApp.BorderStyle.SOLID);
  var turnCell = sheet.getRange(MOVE_CELL);
  turnCell.setValue("Next Turn: Black")
    .setBackground(B_COLOR)
    .setFontColor(W_COLOR);
}

function ensureSheetsExist() {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var names = ["Previous Board", "Before Previous Board"];
  for (var i = 0; i < names.length; i++) {
    var name = names[i];
    var sheet = ss.getSheetByName(name);
    if (!sheet) {
      sheet = ss.insertSheet(name);
      sheet.getRange(BOARD_RANGE)
        .setBackground(BOARD_COLOR)
        .setHorizontalAlignment("center")
        .setVerticalAlignment("middle")
        .setBorder(true, true, true, true, true, true, "black", SpreadsheetApp.BorderStyle.SOLID);
    }
  }
}

function copyBoard(source, target) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sourceSheet = ss.getSheetByName(source);
  var targetSheet = ss.getSheetByName(target);
  if (!sourceSheet || !targetSheet) {
    throw new Error("One of the sheets does not exist: " + source + " or " + target);
  }
  var sourceRange = sourceSheet.getRange(BOARD_RANGE);
  var targetRange = targetSheet.getRange(BOARD_RANGE);
  sourceRange.copyTo(targetRange, SpreadsheetApp.CopyPasteType.PASTE_VALUES, false);
}

function backupBoard() {
  ensureSheetsExist();
  copyBoard("Previous Board", "Before Previous Board");
  copyBoard("Current Board", "Previous Board");
}

function overwriteBoard() {
  ensureSheetsExist();
  copyBoard("Previous Board", "Current Board");
  copyBoard("Before Previous Board", "Previous Board");
}

// --- Test Helpers ---

var testsRun = 0;
var testsPassed = 0;
var testsFailed = 0;
var failures = [];

function assert(condition, message) {
  testsRun++;
  if (!condition) {
    testsFailed++;
    failures.push("FAIL: " + message);
    print("  FAIL: " + message);
  } else {
    testsPassed++;
  }
}

function assertDeepEqual(arr1, arr2, message) {
  testsRun++;
  if (arr1.length !== arr2.length) {
    testsFailed++;
    failures.push("FAIL: " + message + " (length mismatch: " + arr1.length + " vs " + arr2.length + ")");
    print("  FAIL: " + message + " (length mismatch)");
    return;
  }
  for (var r = 0; r < arr1.length; r++) {
    if (arr1[r].length !== arr2[r].length) {
      testsFailed++;
      failures.push("FAIL: " + message + " (row " + r + " length mismatch)");
      print("  FAIL: " + message + " (row " + r + " length mismatch)");
      return;
    }
    for (var c = 0; c < arr1[r].length; c++) {
      if (arr1[r][c] !== arr2[r][c]) {
        testsFailed++;
        failures.push("FAIL: " + message + " at [" + r + "][" + c + "]: got '" + arr1[r][c] + "', expected '" + arr2[r][c] + "'");
        print("  FAIL: " + message + " at [" + r + "][" + c + "]: got '" + arr1[r][c] + "', expected '" + arr2[r][c] + "'");
        return;
      }
    }
  }
  testsPassed++;
}

function fillBoard(sheet, grid) {
  var range = sheet.getRange(BOARD_RANGE);
  range.setValues(grid);
}

function getBoardValues(sheet) {
  return sheet.getRange(BOARD_RANGE).getValues();
}

function placeStone(sheet, row, col, color) {
  var r = row - 1;
  var c = col - 1;
  var range = sheet.getRange(row, col);
  var stone = (color === "B") ? B_STONE : W_STONE;
  range.setValue(stone);
}

// --- Tests ---

function testGetGroup_connected() {
  print("\ntestGetGroup_connected:");
  mockSS = new MockSpreadsheet();
  var current = mockSS.getSheetByName("Current Board");
  var grid = [];
  for (var r = 0; r < 19; r++) {
    grid[r] = [];
    for (var c = 0; c < 19; c++) {
      grid[r][c] = "";
    }
  }
  grid[8][8] = B_STONE;
  grid[8][9] = B_STONE;
  grid[9][8] = B_STONE;
  grid[9][9] = B_STONE;

  var group = getGroup(8, 8, grid);
  assert(group.length === 4, "Connected 2x2 block should have group size 4, got " + group.length);
}

function testGetGroup_notConnected() {
  print("\ntestGetGroup_notConnected:");
  mockSS = new MockSpreadsheet();
  var grid = [];
  for (var r = 0; r < 19; r++) {
    grid[r] = [];
    for (var c = 0; c < 19; c++) {
      grid[r][c] = "";
    }
  }
  grid[8][8] = B_STONE;
  grid[8][10] = B_STONE; // separated by empty cell

  var group1 = getGroup(8, 8, grid);
  assert(group1.length === 1, "Isolated stone should have group size 1, got " + group1.length);

  var group2 = getGroup(8, 10, grid);
  assert(group2.length === 1, "Isolated stone should have group size 1, got " + group2.length);
}

function testGroupHasLiberties_yes() {
  print("\ntestGroupHasLiberties_yes:");
  mockSS = new MockSpreadsheet();
  var grid = [];
  for (var r = 0; r < 19; r++) {
    grid[r] = [];
    for (var c = 0; c < 19; c++) {
      grid[r][c] = "";
    }
  }
  grid[8][8] = B_STONE;

  var group = getGroup(8, 8, grid);
  assert(groupHasLiberties(group, grid) === true, "Single stone should have liberties");
