function testGroupHasLiberties_no() {
  print("\ntestGroupHasLiberties_no:");
  mockSS = new MockSpreadsheet();
  var grid = [];
  for (var r = 0; r < 19; r++) {
    grid[r] = [];
    for (var c = 0; c < 19; c++) {
