function testBackupBoard_shiftsHistory() {
  print("\ntestBackupBoard_shiftsHistory:");
  mockSS = new MockSpreadsheet();

  var current = mockSS.getSheetByName("Current Board");
  var prev = mockSS.insertSheet("Previous Board");
  var beforePrev = mockSS.insertSheet("Before Previous Board");

  // Set up initial states
  fillBoard(current, [
    [B_STONE, "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);
  fillBoard(prev, [
    ["", "", ""],
    ["", W_STONE, ""],
    ["", "", ""],
  ]);
  fillBoard(beforePrev, [
    ["", "", W_STONE],
    ["", "", ""],
    ["", "", ""],
  ]);

  backupBoard();

  // After backup: Before Previous should have old Previous content
  var beforePrevValues = getBoardValues(beforePrev);
  assertDeepEqual(
    [
      ["", "", ""],
      ["", W_STONE, ""],
      ["", "", ""],
    ],
    beforePrevValues.slice(0, 3),
    "Before Previous should now hold old Previous Board (black at 0,0 removed)"
  );

  // After backup: Previous should have old Current content
  var prevValues = getBoardValues(prev);
  assertDeepEqual(
    [
      [B_STONE, "", ""],
      ["", "", ""],
      ["", "", ""],
    ],
    prevValues.slice(0, 3),
    "Previous should now hold old Current Board"
  );

  // Current should be unchanged
  var currentValues = getBoardValues(current);
  assertDeepEqual(
    [
      [B_STONE, "", ""],
      ["", "", ""],
      ["", "", ""],
    ],
    currentValues.slice(0, 3),
    "Current Board should be unchanged after backup"
  );
}

function testBackupBoard_doesNotMakePreviousSameAsCurrentAfterNewMove() {
  print("\ntestBackupBoard_doesNotMakePreviousSameAsCurrentAfterNewMove:");
  // This is the CRITICAL regression test for the main bug.
  // Simulates: Current Board has a stone at (1,1). Player places stone at (1,2).
  // backupBoard() should capture the state BEFORE the new move.
  mockSS = new MockSpreadsheet();

  var current = mockSS.getSheetByName("Current Board");
  var prev = mockSS.insertSheet("Previous Board");
  var beforePrev = mockSS.insertSheet("Before Previous Board");

  // Previous Board is empty
  fillBoard(prev, [
    ["", "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);
  fillBoard(beforePrev, [
    ["", "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);

  // Current Board already has a stone at (1,1) [row 0, col 0 in 0-indexed]
  fillBoard(current, [
    [B_STONE, "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);

  // Simulate placing a new stone at (1,2) [row 0, col 1]
  placeStone(current, 1, 2, "B");

  // Now backup
  backupBoard();

  // Previous Board should have the state BEFORE the new stone was placed
  // i.e., only the stone at (1,1), NOT at (1,2)
  var prevValues = getBoardValues(prev);
  var hasOldStone = prevValues[0][0] === B_STONE;
  var hasNewStone = prevValues[0][1] === B_STONE;

  assert(hasOldStone, "Previous Board should have the old stone at (1,1)");
  assert(!hasNewStone, "Previous Board should NOT have the new stone at (1,2) - this was the main bug");

  // Before Previous should have the old Previous (empty)
  var beforePrevValues = getBoardValues(beforePrev);
  assert(beforePrevValues[0][0] === "", "Before Previous should be empty (from old Previous)");
}

function testOverwriteBoard_undoesMove() {
  print("\ntestOverwriteBoard_undoesMove:");
  mockSS = new MockSpreadsheet();

  var current = mockSS.getSheetByName("Current Board");
  var prev = mockSS.insertSheet("Previous Board");
  var beforePrev = mockSS.insertSheet("Before Previous Board");

  // Set up: Current has stone, Previous has old state
  fillBoard(current, [
    [B_STONE, "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);
  fillBoard(prev, [
    ["", "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);
  fillBoard(beforePrev, [
    ["", "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);

  overwriteBoard();

  // Current should now have the old Previous (empty)
  var currentValues = getBoardValues(current);
  assert(currentValues[0][0] === "", "After undo, Current Board should be empty (restored from Previous)");

  // Previous should now have old Before Previous (empty)
  var prevValues = getBoardValues(prev);
  assert(prevValues[0][0] === "", "After undo, Previous should be empty (restored from Before Previous)");
}

function testFullGameFlow_threeMoves() {
  print("\ntestFullGameFlow_threeMoves:");
  mockSS = new MockSpreadsheet();

  var current = mockSS.getSheetByName("Current Board");
  var prev = mockSS.insertSheet("Previous Board");
  var beforePrev = mockSS.insertSheet("Before Previous Board");

  // Start with empty boards
  fillBoard(current, createEmptyGrid());
  fillBoard(prev, createEmptyGrid());
  fillBoard(beforePrev, createEmptyGrid());

  // Move 1: Black plays (0,0)
  placeStone(current, 1, 1, "B");
  backupBoard();

  var prev1 = getBoardValues(prev);
  assert(prev1[0][0] === B_STONE, "After move 1, Previous Board should have black stone at (0,0)");

  // Move 2: White plays (0,1)
  // First, reset Previous to match current (it should have been backed up already after move 1)
  // We simulate: Current gets new stone
  placeStone(current, 1, 2, "W");
  backupBoard();

  var prev2 = getBoardValues(prev);
  var beforePrev2 = getBoardValues(beforePrev);

  assert(prev2[0][0] === B_STONE && prev2[0][1] === W_STONE,
    "After move 2, Previous should have both stones: black at (0,0) and white at (0,1)");
  assert(beforePrev2[0][0] === B_STONE && beforePrev2[0][1] === "",
    "After move 2, Before Previous should have only the old Previous (black at (0,0) only)");

  // Move 3: Black plays (0,2)
  placeStone(current, 1, 3, "B");
  backupBoard();

  var prev3 = getBoardValues(prev);
  var beforePrev3 = getBoardValues(beforePrev);

  assert(beforePrev3[0][0] === B_STONE && beforePrev3[0][1] === W_STONE && beforePrev3[0][2] === "",
    "After move 3, Before Previous should have the state after move 2 (black at (0,0), white at (0,1))");
  assert(prev3[0][0] === B_STONE && prev3[0][1] === W_STONE && prev3[0][2] === B_STONE,
    "After move 3, Previous should have all 3 stones");
}

