}

function runAllTests() {
  print("==============================");
  print("  Go Board Engine - Test Suite");
  print("==============================");

  testGetGroup_connected();
  testGetGroup_notConnected();
  testGroupHasLiberties_yes();
  testGroupHasLiberties_no();
  testCopyBoard_simple();
  testBackupBoard_shiftsHistory();
