  testOverwriteBoard_undoesMove();
  testFullGameFlow_threeMoves();
  testCheckAndRedraw_removesDeadGroups();
  testCheckAndRedraw_keepsLiveGroups();
  testResetBoard_clearsBoard();
  testCopyBoard_preservesOnlyValues_noFormat();
  testEnsureSheetsExist_createsMissing();
  testEnsureSheetsExist_skipsExisting();
  testCopyBoard_throwsOnMissingSheet();

  print("\n==============================");
