function testBackupBoard_capturesCorrectState() {
  print("\ntestBackupBoard_capturesCorrectState:");
  // Regression test for: "Previous Board was exactly the same as Current Board"
  // and "Before Previous Board never got updated".
  //
  // After placing a stone on Current Board and calling backupBoard():
  // - Previous Board should contain the state of Current Board at that moment (with the new stone)
  // - Before Previous Board should contain the OLD Previous Board state
  // - The key fix: using copyTo() instead of getValues()/setValues() ensures
  //   fresh data is copied, not stale cached values from GAS onEdit context.
  mockSS = new MockSpreadsheet();

  var current = mockSS.getSheetByName("Current Board");
  var prev = mockSS.insertSheet("Previous Board");
  var beforePrev = mockSS.insertSheet("Before Previous Board");

  // Set up realistic state: Previous has a black stone at (0,0)
  fillBoard(prev, [
    [B_STONE, "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);
  // Before Previous is empty
  fillBoard(beforePrev, [
    ["", "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);

  // Current Board has the same as Previous (it was just backed up previously)
  fillBoard(current, [
    [B_STONE, "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);

  // Player places a NEW stone at (0,1) on Current Board
  placeStone(current, 1, 2, "B");

  // Call backupBoard() - this is what happens after each move in the real game
  backupBoard();

  // Previous Board should now have the state WITH the new stone
  var prevValues = getBoardValues(prev);
  assert(prevValues[0][0] === B_STONE, "Previous Board should have old stone at (0,0)");
  assert(prevValues[0][1] === B_STONE, "Previous Board should have new stone at (0,1)");

  // Before Previous should have the OLD Previous state (only old stone at 0,0)
  var beforePrevValues = getBoardValues(beforePrev);
  assert(beforePrevValues[0][0] === B_STONE, "Before Previous should have old Previous stone at (0,0)");
  assert(beforePrevValues[0][1] === "", "Before Previous should NOT have the new stone at (0,1)");

  // Verify: Before Previous and Previous are DIFFERENT (this was the core bug)
  assert(beforePrevValues[0][1] !== prevValues[0][1],
    "Before Previous and Previous must differ — this was the main bug");
}

