18	function onEdit(e) {
19	  const range = e.range;
20	  const sheet = range.getSheet();
21	  const row = range.getRow();
22	  const col = range.getColumn();
23	
24	  if (sheet.getName() !== "Current Board") return;
25	
26	  if (range.getA1Notation() === RESET_CELL) {
27	    range.setValue("");
28	    resetBoard();
29	    backupBoard();
30	    return;
31	  }
32	
33	  if (range.getA1Notation() === UNDO_CELL) {
34	    range.setValue("");
35	    overwriteBoard();
36	    return;
37	  }
38	
39	  if (row < 1 || col < 1 || row > 19 || col > 19) return;
40	
41	  const turnCell = sheet.getRange(MOVE_CELL);
42	  const turnStatus = turnCell.getValue();
43	  let currentTurn = (turnStatus.includes("White") || turnStatus === "W") ? "W" : "B";
44	
45	  const stoneSymbol = (currentTurn === "B") ? B_STONE : W_STONE;
46	
47	  const ss = SpreadsheetApp.getActiveSpreadsheet();
48	  const previousBoardSheet = ss.getSheetByName("Previous Board");
49	  const previousCell = previousBoardSheet.getRange(range.getA1Notation());
50	
51	  if (previousCell.getValue() !== "") { overwriteBoard(); return; }
52	
53	  range.setValue(stoneSymbol);
54	
55	  backupBoard();
56	  
57	  // Run game logic
58	  checkAndRedraw(sheet);
59	
