  // Set up: Previous has one black stone at (0,0)
  fillBoard(prev, [
    [B_STONE, "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);
  // Before Previous is empty
  fillBoard(beforePrev, [
    ["", "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);

  // Current Board is the same as Previous (was backed up last time)
  fillBoard(current, [
    [B_STONE, "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);

  // Simulate onEdit flow: backupBoard() called FIRST, then stone placed
  backupBoard();

  // Previous should now have old Previous (black at 0,0)
  var prevValues = getBoardValues(prev);
  assert(prevValues[0][0] === B_STONE, "Previous should have the old Previous board state");

  // Before Previous should have the OLD Before Previous (empty)
  var beforePrevValues = getBoardValues(beforePrev);
  assert(beforePrevValues[0][0] === "", "Before Previous should have the old empty board");

  // Now place the new stone
  placeStone(current, 1, 1, "B");

  // Previous Board should NOT have the new stone — it captured state BEFORE the move
  assert(prevValues[0][0] === B_STONE, "Previous Board should have the old stone at (0,0)");
  assert(prevValues[0][1] === "", "Previous Board should NOT have a stone at (0,1) — it captured state BEFORE the move");

  // Current Board now has the new stone
  var currentValues = getBoardValues(current);
  assert(currentValues[0][0] === B_STONE, "Current Board should have the new stone at (0,0)");
  assert(currentValues[0][1] === B_STONE, "Current Board should have the new stone at (0,1)");

  // Verify: Previous and Current are DIFFERENT
  assert(prevValues[0][1] !== currentValues[0][1],
    "Previous Board and Current Board must differ — Previous captures state before the move");
}

